MT::Combinatorics c(N, mod);
void solve(int CASE)
{
	ll h, w, n; cin >> h >> w >> n;
	var p = vector<pll>(n + 2);
	fa(i, 1, n)cin >> p[i].px >> p[i].py;
	p[n + 1] = { h,w };
	sort(all1(p));

	var dp = vector<ll>(n + 2);
	fa(i, 1, n + 1) {
		const var& [x, y] = p[i];
		dp[i] = c.lucas(x - 1 + y - 1, x - 1);
		fa(j, 1, i - 1) {
			const var& [nx, ny] = p[j];
			if (x >= nx and y >= ny) {
				ll now = c.lucas(x - nx + y - ny, x - nx);
				dp[i] = ((dp[i] - dp[j] * now % mod) % mod + mod) % mod;
			}
		}
	}
	cout << dp[n + 1] << endl;
	return;
}
